const inboxQuery = String($supportInboxQuery || '').trim();
const ticketCollectionId = String($supportTicketCollectionId || '').trim();
const knowledgeCollectionId = String($supportKnowledgeCollectionId || '').trim();
const missing = [];
if (!ticketCollectionId) missing.push('supportTicketCollectionId');
if (!knowledgeCollectionId) missing.push('supportKnowledgeCollectionId');
if (!inboxQuery) missing.push('supportInboxQuery');
const guidance = [
  'Configuration required before this flow can prepare a grounded support reply draft.',
  missing.length ? `Missing startState keys: ${missing.join(', ')}` : '',
  '',
  'Required setup:',
  '1. Set startState.supportTicketCollectionId to the Collections ticket log collection ID.',
  '2. Set startState.supportKnowledgeCollectionId to the Collections KB collection ID.',
  '3. Set startState.supportInboxQuery to the Gmail inbox filter you want to use.',
  '4. Connect a gmailOAuth2 credential on both Gmail nodes after import.',
  '5. Select a model on the AI Triage + Draft LLM node.'
].filter(Boolean).join('\n');
return {
  hasRequiredConfig: missing.length === 0,
  setupGuidance: guidance
};

const raw = $gmailMessagesRaw;
let parsed = raw;
if (typeof parsed === 'string') {
  try {
    parsed = JSON.parse(parsed);
  } catch {
    parsed = [];
  }
}
const items = Array.isArray(parsed) ? parsed : [];
const email = items[0];
if (!email) {
  return {
    hasEligibleEmail: false,
    sourceMessageId: '',
    sourceThreadId: '',
    sourceFromEmail: '',
    sourceFromName: '',
    sourceSubject: '',
    sourceBody: '',
    kbSearchQuery: ''
  };
}
const fromRaw = String(email.from || '').trim();
const subject = String(email.subject || '').trim();
const body = String(email.body || '').trim();
let sourceFromEmail = fromRaw;
let sourceFromName = '';
const angleMatch = fromRaw.match(/^(.*?)<([^>]+)>$/);
if (angleMatch) {
  sourceFromName = angleMatch[1].replace(/"/g, '').trim();
  sourceFromEmail = angleMatch[2].trim();
}
const normalizedBody = body.replace(/\s+/g, ' ').trim();
const kbSearchQuery = [subject, normalizedBody.slice(0, 700)].filter(Boolean).join(' ');
return {
  hasEligibleEmail: true,
  sourceMessageId: '',
  sourceThreadId: '',
  sourceFromEmail,
  sourceFromName,
  sourceSubject: subject,
  sourceBody: body,
  kbSearchQuery
};

const raw = $kbItemsRaw;
if (typeof raw === 'string') {
  try {
    return JSON.stringify(JSON.parse(raw), null, 2);
  } catch {
    return raw;
  }
}
try {
  return JSON.stringify(raw ?? [], null, 2);
} catch {
  return '[]';
}

