inputs.customFunctionJavascriptFunction:
const clean = (value, fallback = '') => String(value ?? fallback).trim();
const normalizePriority = (value) => {
  const candidate = clean(value, 'normal').toLowerCase();
  return ['low', 'normal', 'high', 'critical'].includes(candidate) ? candidate : 'normal';
};
const normalizeCategory = (value) => {
  const candidate = clean(value, 'other').toLowerCase();
  return ['bug', 'billing', 'access', 'feature_request', 'general_question', 'account', 'integration', 'other'].includes(candidate) ? candidate : 'other';
};
const normalizeTeam = (value) => {
  const candidate = clean(value, clean($defaultAssigneeTeam, 'support')).toLowerCase();
  return ['support', 'product', 'engineering', 'billing', 'ops'].includes(candidate) ? candidate : clean($defaultAssigneeTeam, 'support');
};
let usedKnowledge = $usedKnowledge;
if (typeof usedKnowledge === 'string') {
  try {
    usedKnowledge = JSON.parse(usedKnowledge);
  } catch {
    usedKnowledge = usedKnowledge ? [usedKnowledge] : [];
  }
}
if (!Array.isArray(usedKnowledge)) usedKnowledge = [];
const createdAtIso = new Date().toISOString();
const datePart = createdAtIso.slice(0, 10).replace(/-/g, '');
const shortId = Math.random().toString(36).slice(2, 8).toUpperCase();
const ticketPrefix = clean($ticketPrefix, 'SUP').toUpperCase();
const ticketId = `${ticketPrefix}-${datePart}-${shortId}`;
const sourceSubject = clean($sourceSubject, 'Support request');
const replySubjectRaw = clean($draftReplySubject);
const draftReplySubject = replySubjectRaw || (sourceSubject.toLowerCase().startsWith('re:') ? sourceSubject : `Re: ${sourceSubject}`);
const draftReplyBody = clean($draftReplyBody, 'Thank you for contacting support. We are reviewing your request and will follow up shortly.');
const draftRecipient = clean($sourceFromEmail);
const category = normalizeCategory($triageCategory);
const priority = normalizePriority($triagePriority);
const assignedTeam = normalizeTeam($triageSuggestedTeam);
const summary = clean($triageSummary, sourceSubject);
const nextAction = clean($triageNextAction, 'Review the request and validate the drafted response before sending.');
const needsHumanReview = clean($needsHumanReview, 'true').toLowerCase() === 'true';
const payload = {
  ticketId,
  createdAt: createdAtIso,
  status: clean($defaultStatus, 'draft_ready'),
  gmailMessageId: clean($sourceMessageId),
  gmailThreadId: clean($sourceThreadId),
  fromEmail: clean($sourceFromEmail),
  fromName: clean($sourceFromName),
  subject: sourceSubject,
  messageBody: clean($sourceBody),
  category,
  priority,
  summary,
  assignedTeam,
  nextAction,
  draftReplySubject,
  draftReplyBody,
  usedKnowledge,
  needsHumanReview
};
return {
  ticketId,
  createdAtIso,
  category,
  priority,
  assignedTeam,
  summary,
  nextAction,
  draftReplySubject,
  draftReplyBody,
  draftRecipient,
  usedKnowledge: JSON.stringify(usedKnowledge),
  needsHumanReview,
  ticketRecordPayload: JSON.stringify(payload)
};

